class Solution {
    public int[] pivotArray(int[] nums, int pivot) {
        int n = nums.length;
        int[] result = new int[n];
        int lessIndex = 0, equalIndex = 0, greaterIndex = 0;

        // Count elements less than, equal to, and greater than pivot
        for (int num : nums) {
            if (num < pivot) {
                lessIndex++;
            } else if (num == pivot) {
                equalIndex++;
            } else {
                greaterIndex++;
            }
        }

        int i = 0;
        // Place elements less than pivot
        for (int num : nums) {
            if (num < pivot) {
                result[i++] = num;
            }
        }
        // Place elements equal to pivot
        for (int num : nums) {
            if (num == pivot) {
                result[i++] = num;
            }
        }
        // Place elements greater than pivot
        for (int num : nums) {
            if (num > pivot) {
                result[i++] = num;
            }
        }

        return result;
    }
}
